import{_ as e,o as r,c as i,aA as a}from"./chunks/framework.CebKgM-l.js";const p=JSON.parse('{"title":"Capabilities matrix","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities.md","filePath":"capabilities.md","lastUpdated":null}'),d={name:"capabilities.md"};function l(n,t,s,o,c,h){return r(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="Capabilities-matrix" tabindex="-1">Capabilities matrix <a class="header-anchor" href="#Capabilities-matrix" aria-label="Permalink to &quot;Capabilities matrix {#Capabilities-matrix}&quot;">​</a></h1><p>This page is the source of truth for the public documentation of this branch. It separates what the current code can run from what is only parsed, planned, or present in another development branch.</p><p>For the planned integration path and the version where each future feature can be checked as available, see the <a href="./integration_roadmap">integration roadmap</a>.</p><p>Status legend:</p><ul><li><p><strong>supported</strong>: present in <code>src/</code>, reachable from the public Julia API or <code>.krk</code> runner, and covered by examples or tests in this branch.</p></li><li><p><strong>parser-only</strong>: the <code>.krk</code> parser accepts the syntax, but the v0.1.0 runner rejects or ignores it.</p></li><li><p><strong>not in this branch</strong>: do not document as usable here.</p></li></ul><h2 id="Supported-workflow" tabindex="-1">Supported workflow <a class="header-anchor" href="#Supported-workflow" aria-label="Permalink to &quot;Supported workflow {#Supported-workflow}&quot;">​</a></h2><p>The recommended user path is:</p><ol><li><p>Write or copy a <code>.krk</code> file.</p></li><li><p>Run it with <code>run_simulation(&quot;case.krk&quot;)</code>.</p></li><li><p>Inspect VTK/PNG/GIF outputs.</p></li><li><p>Move to the Julia API only when scripting, callbacks, or custom post-processing are needed.</p></li></ol><h2 id="Core-LBM" tabindex="-1">Core LBM <a class="header-anchor" href="#Core-LBM" aria-label="Permalink to &quot;Core LBM {#Core-LBM}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">2D</th><th style="text-align:center;">3D</th><th style="text-align:center;">GPU path</th><th style="text-align:center;"><code>.krk</code> runner</th><th style="text-align:right;">Reference</th></tr></thead><tbody><tr><td style="text-align:right;">D2Q9 lattice</td><td style="text-align:center;">supported</td><td style="text-align:center;">-</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:right;"><a href="./api/lattice">Lattice</a></td></tr><tr><td style="text-align:right;">D3Q19 lattice</td><td style="text-align:center;">-</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">cavity-style runs</td><td style="text-align:right;"><a href="./theory/06_from_2d_to_3d">From 2D to 3D</a></td></tr><tr><td style="text-align:right;">BGK collision</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:right;"><a href="./theory/03_bgk_collision">BGK</a>, <a href="./api/collision">Collision API</a></td></tr><tr><td style="text-align:right;">Guo body forcing</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported for constant <code>Fx</code>, <code>Fy</code>, <code>Fz</code></td><td style="text-align:right;"><a href="./theory/07_body_forces">Body forces</a></td></tr><tr><td style="text-align:right;">MRT collision</td><td style="text-align:center;">not in this branch</td><td style="text-align:center;">not in this branch</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:right;">planned/development</td></tr><tr><td style="text-align:right;">Axisymmetric LBM</td><td style="text-align:center;">not public in this branch</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:center;">parser rejects at runner</td><td style="text-align:right;">planned/development</td></tr><tr><td style="text-align:right;">Grid refinement</td><td style="text-align:center;">parser-only</td><td style="text-align:center;">parser-only</td><td style="text-align:center;">-</td><td style="text-align:center;">rejected by runner</td><td style="text-align:right;">planned/development</td></tr></tbody></table><h2 id="Boundary-conditions" tabindex="-1">Boundary conditions <a class="header-anchor" href="#Boundary-conditions" aria-label="Permalink to &quot;Boundary conditions {#Boundary-conditions}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Boundary</th><th style="text-align:center;">2D</th><th style="text-align:center;">3D</th><th style="text-align:center;">Spatial expression</th><th style="text-align:center;">Time expression</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">Wall / bounce-back</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:right;">no-slip walls</td></tr><tr><td style="text-align:right;">Velocity / Zou-He</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">west/south/north in 2D</td><td style="text-align:center;">limited</td><td style="text-align:right;">east velocity is not a general public path</td></tr><tr><td style="text-align:right;">Pressure outlet</td><td style="text-align:center;">east in 2D</td><td style="text-align:center;">east/top in 3D</td><td style="text-align:center;">limited</td><td style="text-align:center;">limited</td><td style="text-align:right;">use conservatively</td></tr><tr><td style="text-align:right;">Periodic</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:right;">axis shorthand accepted</td></tr><tr><td style="text-align:right;">Fixed temperature</td><td style="text-align:center;">supported</td><td style="text-align:center;">supported</td><td style="text-align:center;">scalar only</td><td style="text-align:center;">scalar only</td><td style="text-align:right;">thermal module</td></tr><tr><td style="text-align:right;">Symmetry/outflow</td><td style="text-align:center;">parser-recognized</td><td style="text-align:center;">parser-recognized</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:right;">not a validated public BC</td></tr></tbody></table><p>See <a href="./theory/05_boundary_conditions">Boundary conditions</a>, <a href="./theory/19_spatial_bcs">Spatial BCs</a>, and <a href="./krk/bc_types">BC types</a>.</p><h2 id="Thermal" tabindex="-1">Thermal <a class="header-anchor" href="#Thermal" aria-label="Permalink to &quot;Thermal {#Thermal}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:right;">Status</th><th style="text-align:right;">Entry point</th></tr></thead><tbody><tr><td style="text-align:right;">Passive thermal DDF</td><td style="text-align:right;">supported</td><td style="text-align:right;"><code>collide_thermal_2d!</code>, <code>collide_thermal_3d!</code></td></tr><tr><td style="text-align:right;">Fixed-temperature walls</td><td style="text-align:right;">supported</td><td style="text-align:right;"><code>.krk</code> wall <code>T = ...</code>, thermal boundary kernels</td></tr><tr><td style="text-align:right;">Boussinesq natural convection 2D</td><td style="text-align:right;">supported</td><td style="text-align:right;"><code>run_natural_convection_2d</code>, <code>run_rayleigh_benard_2d</code></td></tr><tr><td style="text-align:right;">Natural convection 3D</td><td style="text-align:right;">public Julia API, limited validation</td><td style="text-align:right;"><code>run_natural_convection_3d</code></td></tr><tr><td style="text-align:right;">Temperature-dependent viscosity (<code>Rc</code>)</td><td style="text-align:right;">Julia API only</td><td style="text-align:right;"><code>run_natural_convection_2d(; Rc=...)</code></td></tr><tr><td style="text-align:right;">Thermal grid refinement</td><td style="text-align:right;">not public in this branch</td><td style="text-align:right;">development branch only</td></tr></tbody></table><p>Locally rerun checks on 2026-04-30:</p><ul><li><p>Poiseuille convergence: order 2.00 over <code>Ny = 16, 32, 64, 128</code>.</p></li><li><p>Taylor-Green convergence: order 1.99/2.00/2.00 over <code>N = 16, 32, 64, 128</code>.</p></li><li><p>Thermal conduction: order 1.00 with the current fixed-temperature wall treatment, matching the documented half-cell boundary error.</p></li><li><p>Natural convection at <code>Ra = 1e3</code>, <code>N = 64</code>: <code>Nu = 1.1423</code> versus De Vahl Davis <code>1.118</code>, relative error <code>2.17%</code>.</p></li></ul><h2 id=".krk-DSL" tabindex="-1"><code>.krk</code> DSL <a class="header-anchor" href="#.krk-DSL" aria-label="Permalink to &quot;`.krk` DSL {#.krk-DSL}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Feature</th><th style="text-align:right;">Status</th><th style="text-align:right;">Reference</th></tr></thead><tbody><tr><td style="text-align:right;"><code>Simulation</code>, <code>Domain</code>, <code>Physics</code>, <code>Run</code></td><td style="text-align:right;">supported</td><td style="text-align:right;"><a href="./krk/directives">Directives</a></td></tr><tr><td style="text-align:right;"><code>Define</code> and kwarg overrides</td><td style="text-align:right;">supported</td><td style="text-align:right;"><a href="./krk/directives">Directives</a></td></tr><tr><td style="text-align:right;"><code>Boundary</code></td><td style="text-align:right;">supported with the limits above</td><td style="text-align:right;"><a href="./krk/bc_types">BC types</a></td></tr><tr><td style="text-align:right;"><code>Obstacle</code> / <code>Fluid</code> with expressions</td><td style="text-align:right;">supported</td><td style="text-align:right;"><a href="./krk/directives">Directives</a></td></tr><tr><td style="text-align:right;">STL syntax</td><td style="text-align:right;">parser-only in this branch</td><td style="text-align:right;"><a href="./krk/directives">Directives</a></td></tr><tr><td style="text-align:right;"><code>Initial</code> and <code>Velocity</code> expressions</td><td style="text-align:right;">supported for the generic 2D runner</td><td style="text-align:right;"><a href="./krk/expressions">Expressions</a></td></tr><tr><td style="text-align:right;"><code>Module thermal</code></td><td style="text-align:right;">supported</td><td style="text-align:right;"><a href="./krk/modules">Modules</a></td></tr><tr><td style="text-align:right;"><code>Module axisymmetric</code></td><td style="text-align:right;">parser-visible but runner rejects</td><td style="text-align:right;"><a href="./krk/modules">Modules</a></td></tr><tr><td style="text-align:right;"><code>Refine</code></td><td style="text-align:right;">parser-only; runner rejects</td><td style="text-align:right;"><a href="./krk/directives">Directives</a></td></tr><tr><td style="text-align:right;"><code>Rheology</code></td><td style="text-align:right;">parser-only; runner rejects</td><td style="text-align:right;">planned/development</td></tr><tr><td style="text-align:right;"><code>Sweep</code></td><td style="text-align:right;">parser-supported</td><td style="text-align:right;"><a href="./krk/directives">Directives</a></td></tr></tbody></table><h2 id="Output-and-diagnostics" tabindex="-1">Output and diagnostics <a class="header-anchor" href="#Output-and-diagnostics" aria-label="Permalink to &quot;Output and diagnostics {#Output-and-diagnostics}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Output</th><th style="text-align:right;">Status</th><th style="text-align:right;">Syntax/API</th></tr></thead><tbody><tr><td style="text-align:right;">VTK/PVD</td><td style="text-align:right;">supported</td><td style="text-align:right;"><code>Output vtk every 1000 [rho, ux, uy]</code></td></tr><tr><td style="text-align:right;">PNG snapshots</td><td style="text-align:right;">supported when CairoMakie extension is loaded</td><td style="text-align:right;"><code>Output png every 500 [ux]</code></td></tr><tr><td style="text-align:right;">GIF animations</td><td style="text-align:right;">supported when CairoMakie extension is loaded</td><td style="text-align:right;"><code>Output gif every 100 [ux] fps=15</code></td></tr><tr><td style="text-align:right;">Diagnostics logging</td><td style="text-align:right;">supported</td><td style="text-align:right;"><code>Diagnostics every 100 [step, KE, uMax]</code></td></tr><tr><td style="text-align:right;">ParaView helper</td><td style="text-align:right;">supported</td><td style="text-align:right;"><code>open_paraview(&quot;output/&quot;; name=&quot;case&quot;)</code></td></tr></tbody></table><h2 id="Hardware-and-benchmarks" tabindex="-1">Hardware and benchmarks <a class="header-anchor" href="#Hardware-and-benchmarks" aria-label="Permalink to &quot;Hardware and benchmarks {#Hardware-and-benchmarks}&quot;">​</a></h2><p>The public benchmark story for this branch should use CPU baseline plus H100 only after the corresponding CSV files are present in <code>benchmarks/results/</code>.</p><p>Current traceable artifacts:</p><ul><li><p>Poiseuille convergence CSVs exist for <code>apple_m2</code> and <code>aqua_h100</code>; both match the local rerun exactly.</p></li><li><p>CPU throughput CSVs exist for a legacy <code>apple_m2</code> label.</p></li><li><p>Metal/M3 Max throughput exists as a local artifact, but should not be used as the headline comparison.</p></li><li><p>H100 throughput numbers previously shown in the docs are not backed by a matching CSV in this branch and are therefore not published here.</p></li></ul><p>See <a href="./benchmarks/accuracy">Accuracy</a>, <a href="./benchmarks/performance">Performance</a>, and <a href="./benchmarks/hardware">Hardware</a>.</p><h2 id="Not-public-in-this-branch" tabindex="-1">Not public in this branch <a class="header-anchor" href="#Not-public-in-this-branch" aria-label="Permalink to &quot;Not public in this branch {#Not-public-in-this-branch}&quot;">​</a></h2><p>Do not present the following as usable v0.1.0 features in this documentation:</p><ul><li><p>MRT collision.</p></li><li><p>Axisymmetric Hagen-Poiseuille.</p></li><li><p>Grid refinement / FH patches.</p></li><li><p>Multiphase VOF / PLIC.</p></li><li><p>Phase-field.</p></li><li><p>Shan-Chen.</p></li><li><p>Species transport.</p></li><li><p>Non-Newtonian rheology.</p></li><li><p>Viscoelasticity.</p></li><li><p>SLBM/body-fitted curvilinear work from <code>slbm-paper</code>.</p></li></ul><p>Those items may exist in another branch or design document, but they need separate validation and their own documentation pass before being advertised.</p>',30)])])}const y=e(d,[["render",l]]);export{p as __pageData,y as default};
